themeCSS:
html, body { margin: 0 !important; padding: 0 !important; background: #ffffff !important; width: 100% !important; min-height: 100vh !important; }
body { display: flex !important; flex-direction: column !important; align-items: center !important; }
#container,
#mindmap,
div.mermaid {
  display: flex !important;
  justify-content: center !important;
  align-items: flex-start !important;
  width: 100% !important;
  max-width: 100vw !important;
  flex: 1 0 auto !important;
  box-sizing: border-box !important;
  padding: 48px 64px 96px !important;
}
.mermaid svg {
  margin: 0 auto !important;
  display: block !important;
  max-width: 100% !important;
  height: auto !important;
}
.arrowheadPath,
.marker {
  fill: #000000 !important;
}
